import { useEffect, useState } from 'react';
import API from '../services/api';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';

function Reports() {
  const [report, setReport] = useState(null);

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    const res = await API.get('/reports/monthly');
    setReport(res.data);
  };

  const chartData = [
    { month: 'Jan', leads: 12 },
    { month: 'Feb', leads: 18 },
    { month: 'Mar', leads: 25 },
    { month: 'Apr', leads: 30 }
  ];

  const sourceData = [
    { name: 'Facebook', value: 40 },
    { name: 'Instagram', value: 25 },
    { name: 'Google', value: 35 }
  ];

  const COLORS = ['#6366f1', '#8b5cf6', '#06b6d4'];
  return (
    <div>
      <div className="page-header">
        <div>
          <h2>Reports & Analytics</h2>
          <p>Track admissions performance and lead analytics.</p>
        </div>

        <button className="primary-btn">
          Export CSV
        </button>
      </div>

      <div className="stats-grid">
        <div className="card">
          <h3>Total Leads</h3>
          <h1>{report?.total || 0}</h1>
        </div>

        <div className="card">
          <h3>Admissions</h3>
          <h1>{report?.admitted || 0}</h1>
        </div>

        <div className="card">
          <h3>Conversion Rate</h3>
          <h1>68%</h1>
        </div>
      </div>

      <div className="charts-grid">
        <div className="card chart-card">
          <h3>Monthly Lead Growth</h3>

          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={chartData}>
              <XAxis dataKey="month" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="leads" fill="#6366f1" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="card chart-card">
          <h3>Lead Sources</h3>

          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={sourceData}
                dataKey="value"
                outerRadius={100}
                label
              >
                {sourceData.map((entry, index) => (
                  <Cell
                    key={index}
                    fill={COLORS[index % COLORS.length]}
                  />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
}

export default Reports;
